// components/Navbar.jsx — Sticky top navigation bar
import React, { useState } from "react";
import { NavLink } from "react-router-dom";

const NAV_ITEMS = [
  { label: "Home",     to: "/" },
  { label: "Learn",    to: "/topic/percentages" },
  { label: "Practice", to: "/practice" },
  { label: "Quiz",     to: "/quiz" },
  { label: "Progress", to: "/progress" },
];

export default function Navbar() {
  const [menuOpen, setMenuOpen] = useState(false);

  return (
    <nav className="sticky top-0 z-50 bg-bg border-b border-border">
      <div className="max-w-5xl mx-auto px-5 py-3 flex items-center justify-between">
        {/* Logo */}
        <NavLink to="/" className="flex items-center gap-2 no-underline">
          <span className="font-mono text-accent font-medium text-lg tracking-tight">
            AptiPrep
          </span>
        </NavLink>

        {/* Desktop nav */}
        <ul className="hidden sm:flex items-center gap-7 list-none m-0 p-0">
          {NAV_ITEMS.map(({ label, to }) => (
            <li key={label}>
              <NavLink
                to={to}
                end={to === "/"}
                className={({ isActive }) =>
                  `text-sm transition-colors duration-150 no-underline ${
                    isActive ? "text-accent" : "text-gray-400 hover:text-white"
                  }`
                }
              >
                {label}
              </NavLink>
            </li>
          ))}
        </ul>

        {/* Mobile hamburger */}
        <button
          className="sm:hidden text-gray-400 hover:text-white transition-colors"
          onClick={() => setMenuOpen((v) => !v)}
          aria-label="Toggle menu"
        >
          {menuOpen ? "✕" : "☰"}
        </button>
      </div>

      {/* Mobile dropdown */}
      {menuOpen && (
        <div className="sm:hidden border-t border-border px-5 py-3 flex flex-col gap-3 bg-bg">
          {NAV_ITEMS.map(({ label, to }) => (
            <NavLink
              key={label}
              to={to}
              end={to === "/"}
              onClick={() => setMenuOpen(false)}
              className={({ isActive }) =>
                `text-sm no-underline ${isActive ? "text-accent" : "text-gray-400"}`
              }
            >
              {label}
            </NavLink>
          ))}
        </div>
      )}
    </nav>
  );
}
